api.controller=function() {
  /* widget controller */
  var c = this;
};

sp_widget.css:
/* Pulse Pharmacy Header Styles */
.pulse-header {
  background-color: #E60000;
  border-bottom: 1px solid #B30000;
  box-shadow: 0 2px 8px rgba(0,0,0,0.1);
  font-family: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
}

.pulse-header .navbar-brand {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 15px 15px;
  color: white;
  font-size: 20px;
  font-weight: 700;
  letter-spacing: -0.3px;
}

.pulse-header .navbar-brand .brand-icon {
  font-size: 24px;
}

.pulse-header .navbar-brand .brand-name {
  font-weight: 700;
}

.pulse-header .navbar-brand .brand-tagline {
  font-size: 12px;
  font-weight: 400;
  opacity: 0.85;
  margin-left: 6px;
}

.pulse-header .nav > li > a {
  color: white;
  font-weight: 500;
  transition: all 0.2s ease;
}

.pulse-header .nav > li > a:hover,
.pulse-header .nav > li > a:focus {
  background-color: rgba(255,255,255,0.15);
  color: white;
}

.pulse-header .nav .dropdown-menu > li > a:hover {
  background-color: #E60000;
  color: white;
}

.pulse-header .navbar-toggle {
  border-color: rgba(255,255,255,0.5);
}

.pulse-header .navbar-toggle .icon-bar {
  background-color: white;
}

.pulse-header .navbar-collapse {
  border-top-color: rgba(255,255,255,0.2);
}
